private boolean testValidProtocol(Element el, Attribute attr, Set<Protocol> protocols) {
    // try to resolve relative urls to abs, and optionally update the attribute so output html has abs.
    // rels without a baseuri get removed
    String value = attr.getValue();
    String absValue = el.absUrl(attr.getKey());

    // Only use the absolute URL value if it's not empty and the original value wasn't a custom protocol
    boolean hasProtocol = false;
    for (Protocol protocol : protocols) {
        String prot = protocol.toString() + ":";
        if (value.toLowerCase().startsWith(prot)) {
            hasProtocol = true;
            break;
        }
    }

    if (hasProtocol) {
        // If the original value already has a valid protocol, test against it directly
        if (!preserveRelativeLinks) {
            attr.setValue(value); // Keep the original value
        }
        for (Protocol protocol : protocols) {
            String prot = protocol.toString() + ":";
            if (value.toLowerCase().startsWith(prot)) {
                return true;
            }
        }
    } else {
        // Original behavior for relative URLs
        if (!preserveRelativeLinks)
            attr.setValue(absValue);

        for (Protocol protocol : protocols) {
            String prot = protocol.toString() + ":";
            if (absValue.toLowerCase().startsWith(prot)) {
                return true;
            }
        }
    }
    return false;
}

